function solve(nums: number[], queries: number[][]): number[] {
    // Precompute popcount-depth for each number in nums
    const popcount_depths: number[] = nums.map((num) => {
        let depth = 0;
        let current = num;
        while (current > 0) {
            current = current.toString(2).split('1').length;
            depth += 1;
            if (current === 1) break;
        }
        return depth;
    });

    // Segment tree implementation
    class SegmentTree {
        private size: number;
        private tree: number[];
        private lazy: number[];

        constructor(data: number[]) {
            this.size = data.length;
            this.tree = new Array(4 * this.size).fill(0);
            this.lazy = new Array(4 * this.size).fill(0);
            this.build(1, 0, this.size - 1, data);
        }

        private build(node: number, l: number, r: number, data: number[]): void {
            if (l === r) {
                this.tree[node] = data[l];
                return;
            }
            const mid = Math.floor((l + r) / 2);
            this.build(2 * node, l, mid, data);
            this.build(2 * node + 1, mid + 1, r, data);
            this.tree[node] = this.tree[2 * node] + this.tree[2 * node + 1];
        }

        private pushDown(node: number, l: number, r: number): void {
            if (this.lazy[node] !== 0 && l !== r) {
                const mid = Math.floor((l + r) / 2);
                const leftNode = 2 * node;
                const rightNode = 2 * node + 1;
                this.tree[leftNode] = this.lazy[node] * (mid - l + 1);
                this.lazy[leftNode] = this.lazy[node];
                this.tree[rightNode] = this.lazy[node] * (r - mid);
                this.lazy[rightNode] = this.lazy[node];
                this.lazy[node] = 0;
            }
        }

        private updateRange(node: number, l: number, r: number, ul: number, ur: number, value: number): void {
            if (ur < l || r < ul) {
                return;
            }
            if (ul <= l && r <= ur) {
                this.tree[node] = value * (r - l + 1);
                this.lazy[node] = value;
                return;
            }
            this.pushDown(node, l, r);
            const mid = Math.floor((l + r) / 2);
            this.updateRange(2 * node, l, mid, ul, ur, value);
            this.updateRange(2 * node + 1, mid + 1, r, ul, ur, value);
            this.tree[node] = this.tree[2 * node] + this.tree[2 * node + 1];
        }

        private queryRange(node: number, l: number, r: number, ql: number, qr: number): number {
            if (qr < l || r < ql) {
                return 0;
            }
            if (ql <= l && r <= qr) {
                return this.tree[node];
            }
            this.pushDown(node, l, r);
            const mid = Math.floor((l + r) / 2);
            const left = this.queryRange(2 * node, l, mid, ql, qr);
            const right = this.queryRange(2 * node + 1, mid + 1, r, ql, qr);
            return left + right;
        }

        public update(idx: number, value: number): void {
            this.updateRange(1, 0, this.size - 1, idx, idx, value);
        }

        public query(l: number, r: number): number {
            return this.queryRange(1, 0, this.size - 1, l, r);
        }
    }

    // Create segment tree
    const st = new SegmentTree(popcount_depths);

    // Process queries
    const answer: number[] = [];

    for (const query of queries) {
        if (query[0] === 1) {
            const l = query[1];
            const r = query[2];
            const k = query[3];
            // Since the segment tree stores the popcount-depths, we need to query for value k
            answer.push(st.query(l, r));
        } else {
            const idx = query[1];
            const val = query[2];
            // Update the value and recompute the popcount-depth
            let new_val = val;
            let new_depth = 0;
            let current = new_val;
            while (current > 0) {
                current = current.toString(2).split('1').length;
                new_depth += 1;
                if (current === 1) break;
            }
            st.update(idx, new_depth);
        }
    }

    return answer;
}
